// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
// Optimized Hybrid Quicksort: Iterative tail-call, 3-way partitioning
// for duplicate keys, median-of-three pivot, and sorted detection.

pub fn adaptive_sort<T: Ord + Clone>(mut arr: &mut [T]) {
    while arr.len() > 24 {
        let n = arr.len();
        let (mut asc, mut desc) = (true, true);
        for i in 1..n {
            if arr[i-1] > arr[i] { asc = false; } else if arr[i-1] < arr[i] { desc = false; }
            if !asc && !desc { break; }
        }
        if asc { return; } if desc { arr.reverse(); return; }

        let pivot = {
            let (m, h) = (n / 2, n - 1);
            if arr[m] < arr[0] { arr.swap(0, m); }
            if arr[h] < arr[0] { arr.swap(0, h); }
            if arr[h] < arr[m] { arr.swap(m, h); }
            arr[m].clone()
        };

        let (mut l, mut i, mut g) = (0, 0, n - 1);
        while i <= g {
            match arr[i].cmp(&pivot) {
                Ordering::Less => { arr.swap(l, i); l += 1; i += 1; }
                Ordering::Greater => { arr.swap(i, g); g -= 1; }
                Ordering::Equal => i += 1,
            }
        }
        if l < n - g - 1 {
            adaptive_sort(&mut arr[..l]);
            arr = &mut arr[g + 1..];
        } else {
            adaptive_sort(&mut arr[g + 1..]);
            arr = &mut arr[..l];
        }
    }
    for i in 1..arr.len() {
        let mut j = i;
        while j > 0 && arr[j - 1] > arr[j] { arr.swap(j, j - 1); j -= 1; }
    }
}
